-- Align holidays with imported CSV (semicolon-delimited export)
insert into public.holiday_types (code, name) values
  ('State', 'US State / local'),
  ('Food', 'Food & drink')
on conflict (code) do nothing;

alter table public.holidays add column if not exists origin text;

-- CSV uses textual rules (e.g. Last Monday); original migration used smallint
alter table public.holidays alter column rule_day type text using (
  case
    when rule_day is null then null
    else rule_day::text
  end
);

delete from public.holidays;

